// init_summary is now in the Supabase rows (already queried by SB extract profile)
const rows = $input.all().map(item => item.json);

const report = rows.reduce((acc, row) => {
  // Map init_summary section_type to initial_summary key (for prompt compatibility)
  if (row.section_type === 'init_summary') {
    acc.initial_summary = row.content;
  } else {
    acc[row.section_type] = row.content;
  }
  return acc;
}, {
  report_id: rows[0]?.report_id || null
});

return [{ json: report }];

const raw = $json.text;

const jsonMatch = raw.match(/```json\n([\s\S]*?)\n```/);
if (!jsonMatch) {
  throw new Error("Could not find a JSON block in the input text.");
}

const cleanJsonString = jsonMatch[1].trim();

let parsed;
try {
  parsed = JSON.parse(cleanJsonString);
} catch (e) {
  throw new Error("Failed to parse extracted JSON. Error: " + e.message);
}

function normalizeKey(str) {
  if (!str) return '';
  return str
    .toLowerCase()
    .replace(/[—–-]/g, '-')
    .replace(/&/g, 'and')
    .replace(/[^\w\s-]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

// Build lookup from suitable_15 with multiple matching strategies
const suitable15Raw = $('suitable_15').item.json.text;
const s15Match = suitable15Raw.match(/```json\n([\s\S]*?)\n```/);
let s15Careers = [];

if (s15Match) {
  try {
    const s15Parsed = JSON.parse(s15Match[1].trim());
    s15Careers = s15Parsed.careers || [];
  } catch (e) {
    // continue without path data
  }
}

const byTitleAndSize = {};
const byTitle = {};

s15Careers.forEach(c => {
  const t = normalizeKey(c.career_title);
  const ts = `${t}||${normalizeKey(c.company_size_type)}`;
  byTitleAndSize[ts] = c;
  byTitle[t] = c;
});

return parsed.map((item, idx) => {
  const t = normalizeKey(item.career_title);
  const ts = `${t}||${normalizeKey(item.company_size_type)}`;

  // Match by title+company first (most precise), then title alone,
  // then fall back to position if the array lengths align
  let match = byTitleAndSize[ts] || byTitle[t];
  if (!match && s15Careers.length === parsed.length) {
    match = s15Careers[idx];
  }

  const formatted =
    `Career Title: ${item.career_title}\n` +
    `Company: ${item.company_size_type}\n` +
    `AI Impact: ${item.ai_impact_rating?.rating} - ${item.ai_impact_rating?.explanation}\n` +
    `Exp. salary range in ${item.salary?.region}: ${item.salary?.range}`;

  return {
    json: {
      ...item,
      path_type: match?.path_type || null,
      path_type_notes: match?.path_type_notes || null,
      formatted_output: formatted
    }
  };
});

// Get the 15 new careers from Tit_and_Co1
const titAndCoItems = $("Tit_and_Co1").all().map(item => item.json);

// In-batch dedup (case/whitespace normalized)
function normalize(str) {
  if (!str) return '';
  return str.toLowerCase().replace(/\s+/g, ' ').trim();
}

const seenKeys = new Set();
const uniqueCareers = [];

titAndCoItems.forEach(career => {
  const key = normalize(`${career.career_title}||${career.company_size_type}`);
  if (!seenKeys.has(key)) {
    seenKeys.add(key);
    uniqueCareers.push(career);
  }
});

// Return one item per career so Batcher1 can group them
return uniqueCareers.map(c => ({ json: c }));

const careers = items.map(i => i.json);
const batchSize = 5;
const batches = [];

for (let i = 0; i < careers.length; i += batchSize) {
  batches.push(careers.slice(i, i + batchSize));
}

return batches.map(batch => ({
