function cleanText(str) {
  return str
    .replace(/```(?:json)?/g, "")
    .replace(/```/g, "")
    .trim();
}

function safeParse(str) {
  try {
    return JSON.parse(str);
  } catch {
    return null;
  }
}

function normalize(data) {
  if (!data) return [];

  if (Array.isArray(data)) return data;
  if (typeof data === "object") return [data];

  if (typeof data === "string") {
    const cleaned = cleanText(data);

    if (cleaned.startsWith("[") && cleaned.endsWith("]")) {
      try { return JSON.parse(cleaned); } catch {}
    }

    const matches = cleaned.match(/\{[\s\S]*?\}(?=\s*\{|\s*$)/g);
    if (matches) {
      const parsed = matches.map(m => safeParse(m)).filter(Boolean);
      if (parsed.length > 0) return parsed;
    }

    const obj = safeParse(cleaned);
    if (obj) return [obj];
  }

  return [];
}

function enforceMinimums(obj) {
  const rules = {
    technical_skills: 3,
    soft_skills: 3,
    core_values: 3,
    motivational_factors: 3,
    typical_tasks: 4,
  };

  for (const [field, minCount] of Object.entries(rules)) {
    if (!Array.isArray(obj[field])) obj[field] = [];
    while (obj[field].length < minCount) {
      obj[field].push("N/A");
    }
  }

  return obj;
}

function sanitize(obj) {
  if (Array.isArray(obj)) {
    return obj.map(sanitize);
  } else if (obj !== null && typeof obj === "object") {
    const clean = {};
    for (const [k, v] of Object.entries(obj)) {
      clean[k] = v === undefined ? null : sanitize(v);
    }
    return clean;
  }
  return obj;
}


// 🔹 MAIN EXECUTION
const allInputs = $input.all();
let allItems = [];

const schemaTemplate = {
  career_title: "N/A",
  company_size_type: "N/A",
  overview: "N/A",
  technical_skills: [],
  soft_skills: [],
  personality_traits: "N/A",
  work_schedule: "N/A",
  client_interaction: "N/A",
  colleague_interaction: "N/A",
  autonomy_vs_collaboration: "N/A",
  pace_of_work: "N/A",
  core_values: [],
  motivational_factors: [],
  typical_tasks: [],
  education_requirements: "N/A",
  certifications_requirements: "N/A",
  career_progression: [],
  ai_impact_rating: { rating: "N/A", explanation: "N/A" },
  salary: { region: "N/A", range: "N/A" },
  alternate_titles: [],
  leadership_challenges: [],
  path_type: "N/A",
  path_type_notes: "N/A"
};

for (const item of allInputs) {
  // 1. Get the raw input (it's in the "text" field based on your snippet)
  const rawData = item.json.text || item.json;

  // 2. Use your normalize function to parse the stringified JSON
  const parsedItems = normalize(rawData);

  // 3. Process each parsed career
  if (Array.isArray(parsedItems)) {
    const processedBatch = parsedItems.map(obj => {
      const processed = enforceMinimums(sanitize(obj));
      return { ...schemaTemplate, ...processed };
    });
    allItems.push(...processedBatch);
  }
}

// Final check to prevent n8n error
if (allItems.length === 0) {
  return [{ json: { message: "No items found in input" } }];
}

return allItems.map(i => ({ json: i }));

// Extract region from init_summary without LLM call
// Region is question 1d - a fixed dropdown value
const summary = $json.initial_summary || '';

const VALID_REGIONS = [
  'Northern and Western Europe',
  'Southern and Eastern Europe',
  'United Kingdom (London)',
  'United Kingdom (Other)',
  'United States (High-Cost Regions)',
  'United States (Average-Cost Regions)',
  'United States (Lower-Cost Regions)',
  'Canada',
  'Australia and New Zealand',
  'Switzerland'
];

// Try to find the region in the summary text
let region = 'Northern and Western Europe'; // safe default

for (const r of VALID_REGIONS) {
  if (summary.includes(r)) {
    region = r;
    break;
  }
}

return [{ json: { Region: region } }];

